INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES
(1, 1, 'Một người bình luận WordPress', 'wapuu@wordpress.example', 'https://vi.wordpress.org/', '', '2026-03-25 06:15:10', '2026-03-25 06:15:10', 'Xin chào, đây là một bình luận.\nĐể bắt đầu kiểm duyệt, chỉnh sửa và xóa nhận xét, vui lòng truy cập màn hình Nhận xét trong trang quản trị.\nHình đại diện của người bình luận đến từ <a href=\"https://gravatar.com/\">Gravatar</a>.', 0, '1', '', 'comment', 0, 0),
(2, 24, 'Alan', 'architecture.pencidesign@gmail.com', 'http://pencidesign.com', '113.190.175.141', '2017-07-17 03:39:38', '2017-07-17 03:39:38', 'Et harum quidem rerum facilis est et expedita distinctio. Nam libero tempore, cum soluta nobis est eligendi optio cumque nihil impedit quo minus id quod maxime placeat facere.', 0, '1', '', 'comment', 0, 0),
(3, 24, 'Alan', 'architecture.pencidesign@gmail.com', 'http://pencidesign.com', '113.190.175.141', '2017-07-17 03:40:50', '2017-07-17 03:40:50', 'Quis autem vel eum iure reprehenderit qui in ea voluptate velit esse quam nihil.', 0, '1', '', 'comment', 2, 0),
(4, 24, 'Alan', 'architecture.pencidesign@gmail.com', 'http://pencidesign.com', '113.190.175.141', '2017-07-17 03:41:50', '2017-07-17 03:41:50', 'Neque porro quisquam est, qui dolorem ipsum quia dolor sit amet, consectetur, adipisci velit, sed quia non numquam eius modi tempora incidunt ut labore.', 0, '1', '', 'comment', 0, 0),
